import java.io.IOException;
import java.io.PrintWriter;

import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by sanitizing and encoding it before outputting to HTML
        try {
            PrintWriter writer = new PrintWriter("output.html", "UTF-8");
            writer.println("<html>");
            writer.println("<head><title>XSS Fixed Example</title></head>");
            writer.println("<body>");
            writer.println("<h1>Hello, " + StringEscapeUtils.escapeHtml4(userInput) + "</h1>"); // Sanitize and encode user input
            writer.println("</body>");
            writer.println("</html>");
            writer.close();
        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }
}

